import{_ as a,C as d,o as r,c as s,E as l,a3 as i}from"./chunks/framework.COIRw5e5.js";const o="/versions/v0.11.0/screens/devices/chance.png",b=JSON.parse('{"title":"Chance","description":"","frontmatter":{"title":"Chance","pageClass":"device-doc"},"headers":[],"relativePath":"devices/chance.md","filePath":"devices/chance.md"}'),n={name:"devices/chance.md"};function h(c,t,g,p,y,m){const e=d("DeviceHeading");return r(),s("div",null,[l(e,{slug:"chance",title:"Chance"}),t[0]||(t[0]=i('<p>Probabilistic note gate</p><p><img src="'+o+'" alt="Chance parameters" class="screen"></p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Insert <strong>Chance</strong> to <strong>probabilistically pass or drop</strong> notes (and optionally scale surviving velocity). Use rate to thin a dense stream over time.</p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><div class="device-params-table"><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Bypass</td><td>0 – 1</td><td>When on, the device is disabled and MIDI passes through unchanged.</td></tr><tr><td>Chance</td><td>0 – 100</td><td>Probability (0–100%) that a note is allowed through.</td></tr><tr><td>Rate</td><td>0</td><td>Clock division for each step — how fast the pattern advances.</td></tr><tr><td>Use Velocity</td><td>0 – 1</td><td>When on, dropped notes scale remaining velocity instead of a hard mute.</td></tr></tbody></table></div><h2 id="parameter-values" tabindex="-1">Parameter values <a class="header-anchor" href="#parameter-values" aria-label="Permalink to &quot;Parameter values&quot;">​</a></h2><h3 id="bypass" tabindex="-1">Bypass <a class="header-anchor" href="#bypass" aria-label="Permalink to &quot;Bypass&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Device is active and processes MIDI.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Device is bypassed; messages pass through unchanged.</td></tr></tbody></table><h3 id="rate" tabindex="-1">Rate <a class="header-anchor" href="#rate" aria-label="Permalink to &quot;Rate&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>No rate thinning — only per-note chance applies.</td></tr><tr><td style="text-align:right;">1</td><td>1/1</td><td>Allow roughly one message per 1/1 clock slice.</td></tr><tr><td style="text-align:right;">2</td><td>1/2</td><td>Allow roughly one message per 1/2 clock slice.</td></tr><tr><td style="text-align:right;">3</td><td>1/4</td><td>Allow roughly one message per 1/4 clock slice.</td></tr><tr><td style="text-align:right;">4</td><td>1/8</td><td>Allow roughly one message per 1/8 clock slice.</td></tr><tr><td style="text-align:right;">5</td><td>1/16</td><td>Allow roughly one message per 1/16 clock slice.</td></tr><tr><td style="text-align:right;">6</td><td>1/32</td><td>Allow roughly one message per 1/32 clock slice.</td></tr><tr><td style="text-align:right;">7</td><td>1/64</td><td>Allow roughly one message per 1/64 clock slice.</td></tr></tbody></table><h3 id="use-velocity" tabindex="-1">Use Velocity <a class="header-anchor" href="#use-velocity" aria-label="Permalink to &quot;Use Velocity&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Dropped notes are silent.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Passed notes keep proportional velocity.</td></tr></tbody></table>',13))])}const v=a